package genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter_type.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter_type.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter_type.mapper.VehicleFilterTypeMapper; import genxsolution.vms.vmsbackend.maintenance_management.vehicle_filter_type.repository.VehicleFilterTypeRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleFilterTypeService { private final VehicleFilterTypeRepository repository; private final VehicleFilterTypeMapper mapper; public VehicleFilterTypeService(VehicleFilterTypeRepository repository,VehicleFilterTypeMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleFilterTypeResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleFilterTypeResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleFilterType", String.valueOf(id))); } public VehicleFilterTypeResponse create(VehicleFilterTypeUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleFilterTypeResponse update(UUID id,VehicleFilterTypeUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("VehicleFilterType", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("VehicleFilterType", String.valueOf(id)); } }
